#include <string.h>
#include <ctype.h>

/*
 * json_extract_int: extracts an int64 from a JSON value at a given dot-separated path.
 * Returns 0 on success, non-zero on error.
 * Single-pass, no heap allocation, no full parse tree.
 * The parser cannot read past the null terminator because it always checks for '\0'
 * before advancing the pointer, and all loops terminate on '\0' or mismatch.
 */

static int skip_whitespace(const char **p) {
    while (**p == ' ' || **p == '\t' || **p == '\n' || **p == '\r')
        (*p)++;
    return 0;
}

static int parse_string(const char **p) {
    if (**p != '"') return 1;
    (*p)++; // skip opening quote
    while (**p) {
        if (**p == '\\') {
            (*p)++;
            if (!**p) return 1; // unterminated escape
            switch (**p) {
                case '"': case '\\': case '/': case 'b': case 'f': case 'n': case 'r': case 't':
                    (*p)++;
                    break;
                case 'u':
                    for (int i = 0; i < 4; i++) {
                        (*p)++;
                        if (!isxdigit(**p)) return 1;
                    }
                    break;
                default: return 1;
            }
        } else if (**p == '"') {
            (*p)++; // skip closing quote
            return 0;
        } else if (**p < 0x20) {
            return 1; // control character
        } else {
            (*p)++;
        }
    }
    return 1; // unterminated string
}

static int parse_number(const char **p, int64_t *out) {
    const char *start = *p;
    int negative = 0;
    int64_t value = 0;

    if (**p == '-') {
        negative = 1;
        (*p)++;
        if (!isdigit(**p)) return 1; // just '-'
    }
    if (**p == '0') {
        (*p)++;
        if (isdigit(**p)) return 1; // leading zero
    } else if (isdigit(**p)) {
        while (isdigit(**p)) (*p)++;
    } else {
        return 1; // not a number
    }

    // reject fractional part
    if (**p == '.') return 1;
    // reject exponent
    if (**p == 'e' || **p == 'E') return 1;

    // parse digits we already passed
    const char *digits = start;
    if (*digits == '-') digits++;
    while (digits < *p) {
        if (value > INT64_MAX / 10) return 1; // overflow
        value = value * 10 + (*digits - '0');
        digits++;
    }
    if (negative) value = -value;

    // check for trailing non-digit (should not happen if we consumed correctly)
    if (**p != ',' && **p != '}' && **p != ']' && **p != ' ' && **p != '\t' && **p != '\n' && **p != '\r' && **p != '\0')
        return 1;

    *out = value;
    return 0;
}

static int skip_value(const char **p);

static int parse_array(const char **p) {
    if (**p != '[') return 1;
    (*p)++; // skip '['
    skip_whitespace(p);
    if (**p == ']') {
        (*p)++;
        return 0;
    }
    for (;;) {
        if (skip_value(p)) return 1;
        skip_whitespace(p);
        if (**p == ']') {
            (*p)++;
            return 0;
        }
        if (**p != ',') return 1;
        (*p)++;
        skip_whitespace(p);
    }
}

static int parse_object(const char **p) {
    if (**p != '{') return 1;
    (*p)++; // skip '{'
    skip_whitespace(p);
    if (**p == '}') {
        (*p)++;
        return 0;
    }
    for (;;) {
        if (parse_string(p)) return 1;
        skip_whitespace(p);
        if (**p != ':') return 1;
        (*p)++;
        skip_whitespace(p);
        if (skip_value(p)) return 1;
        skip_whitespace(p);
        if (**p == '}') {
            (*p)++;
            return 0;
        }
        if (**p != ',') return 1;
        (*p)++;
        skip_whitespace(p);
    }
}

static int skip_value(const char **p) {
    skip_whitespace(p);
    switch (**p) {
        case '"': return parse_string(p);
        case '{': return parse_object(p);
        case '[': return parse_array(p);
        case 't':
            if (strncmp(*p, "true", 4) == 0) { *p += 4; return 0; }
            return 1;
        case 'f':
            if (strncmp(*p, "false", 5) == 0) { *p += 5; return 0; }
            return 1;
        case 'n':
            if (strncmp(*p, "null", 4) == 0) { *p += 4; return 0; }
            return 1;
        case '-': case '0': case '1': case '2': case '3': case '4':
        case '5': case '6': case '7': case '8': case '9': {
            int64_t dummy;
            return parse_number(p, &dummy);
        }
        default: return 1;
    }
}

// Main function
int json_extract_int(const char *json, const char *path, int64_t *out) {
    if (!json || !path || !out) return 1;

    const char *p = json;
    skip_whitespace(&p);

