// Stats returns a consistent snapshot of pool metrics.
func (p *BoundedWorkerPool) Stats() Stats {
	p.mu.Lock()
	defer p.mu.Unlock()
	return Stats{
		InFlight:        p.inFlight,
		QueueDepth:      len(p.taskQueue),
		TotalSubmitted:  atomic.LoadInt64(&p.totalSubmitted),
		TotalCompleted:  atomic.LoadInt64(&p.totalCompleted),
		TotalPanics:     atomic.LoadInt64(&p.totalPanics),
		TotalRejected:   atomic.LoadInt64(&p.totalRejected),
	}
}

// worker is a single worker goroutine.
func (p *BoundedWorkerPool) worker() {
	defer p.workerWg.Done()
	for {
		select {
		case task, ok := <-p.taskQueue:
			if !ok {
				// queue closed (shutdown)
				return
			}
			p.mu.Lock()
			p.inFlight++
			p.mu.Unlock()
			err := p.executeTask(task)
			p.mu.Lock()
			p.inFlight--
			p.mu.Unlock()
			atomic.AddInt64(&p.totalCompleted, 1)
			// send error to task's result channel (not shown in this simplified version)
			_ = err
		case <-p.shutdownCh:
			return
		}
	}
}

// executeTask runs a task and recovers panics.
func (p *BoundedWorkerPool) executeTask(task taskFunc) (err error) {
	defer func() {
		if r := recover(); r != nil {
			atomic.AddInt64(&p.totalPanics, 1)
			err = fmt.Errorf("panic: %v", r)
		}
	}()
	return task()
}
